--
-- Name: handle_new_user(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.handle_new_user() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  user_name TEXT;
BEGIN
  -- L???y t??n t??? metadata (??u ti??n full_name, sau ???? name, cu???i c??ng l?? email prefix)
  user_name := COALESCE(
    NEW.raw_user_meta_data->>'full_name',
    NEW.raw_user_meta_data->>'name',
    split_part(COALESCE(NEW.email, 'unknown@example.com'), '@', 1)
  );
  
  -- Th??? insert v??o profiles v???i error handling
  BEGIN
    -- Ki???m tra xem c???t n??o t???n t???i v?? c???p nh???t c??? hai n???u c??
    IF EXISTS (SELECT 1 FROM information_schema.columns 
               WHERE table_schema = 'public' 
               AND table_name = 'profiles' 
               AND column_name = 'full_name') THEN
      -- C?? full_name - c???p nh???t c??? full_name v?? name (n???u c??)
      IF EXISTS (SELECT 1 FROM information_schema.columns 
                 WHERE table_schema = 'public' 
                 AND table_name = 'profiles' 
                 AND column_name = 'name') THEN
        -- C?? c??? hai c???t - c???p nh???t c??? hai
        INSERT INTO public.profiles (id, email, full_name, name)
        VALUES (NEW.id, COALESCE(NEW.email, ''), user_name, user_name)
        ON CONFLICT (id) DO UPDATE SET
          email = COALESCE(EXCLUDED.email, profiles.email),
          full_name = COALESCE(EXCLUDED.full_name, profiles.full_name),
          name = COALESCE(EXCLUDED.name, profiles.name);
      ELSE
        -- Ch??? c?? full_name
        INSERT INTO public.profiles (id, email, full_name)
        VALUES (NEW.id, COALESCE(NEW.email, ''), user_name)
        ON CONFLICT (id) DO UPDATE SET
          email = COALESCE(EXCLUDED.email, profiles.email),
          full_name = COALESCE(EXCLUDED.full_name, profiles.full_name);
      END IF;
    ELSE
      -- Ch??? c?? name (kh??ng c?? full_name)
      INSERT INTO public.profiles (id, email, name)
      VALUES (NEW.id, COALESCE(NEW.email, ''), user_name)
      ON CONFLICT (id) DO UPDATE SET
        email = COALESCE(EXCLUDED.email, profiles.email),
        name = COALESCE(EXCLUDED.name, profiles.name);
    END IF;
  EXCEPTION WHEN OTHERS THEN
    -- Log error nh??ng kh??ng fail trigger
    RAISE WARNING 'Error in handle_new_user: %', SQLERRM;
    -- V???n return NEW ????? kh??ng block user creation
  END;
  
  RETURN NEW;
END;
$$;


--
-- Name: handle_new_user_role(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.handle_new_user_role() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  user_count integer;
BEGIN
  BEGIN
    SELECT COUNT(*) INTO user_count FROM public.user_roles;
    
    IF user_count = 0 THEN
      INSERT INTO public.user_roles (user_id, role) VALUES (NEW.id, 'admin'::public.app_role)
      ON CONFLICT (user_id) DO NOTHING;
    ELSE
      INSERT INTO public.user_roles (user_id, role) VALUES (NEW.id, 'user'::public.app_role)
      ON CONFLICT (user_id) DO NOTHING;
    END IF;
  EXCEPTION WHEN OTHERS THEN
    -- Log error nh??ng kh??ng fail trigger
    RAISE WARNING 'Error in handle_new_user_role: %', SQLERRM;
  END;
  
  RETURN NEW;
END;
$$;


