--

CREATE FUNCTION public.increment_api_key_usage(_key_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  UPDATE public.api_keys
  SET 
    usage_count = usage_count + 1,
    current_usage_today = current_usage_today + 1,
    current_usage_month = current_usage_month + 1,
    last_used_at = now(),
    updated_at = now()
  WHERE id = _key_id;
END;
$$;


--
-- Name: log_life_milestone_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_life_milestone_change() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  action_type TEXT;
  old_data_json JSONB;
  new_data_json JSONB;
  changed_fields_array TEXT[];
BEGIN
  IF TG_OP = 'INSERT' THEN
    action_type := 'created';
    new_data_json := to_jsonb(NEW);
    old_data_json := NULL;
    changed_fields_array := ARRAY[]::TEXT[];
  ELSIF TG_OP = 'UPDATE' THEN
    action_type := 'updated';
    old_data_json := to_jsonb(OLD);
    new_data_json := to_jsonb(NEW);
    changed_fields_array := ARRAY[]::TEXT[];
    IF OLD.title IS DISTINCT FROM NEW.title THEN changed_fields_array := array_append(changed_fields_array, 'title'); END IF;
    IF OLD.description IS DISTINCT FROM NEW.description THEN changed_fields_array := array_append(changed_fields_array, 'description'); END IF;
    IF OLD.date IS DISTINCT FROM NEW.date THEN changed_fields_array := array_append(changed_fields_array, 'date'); END IF;
    IF OLD.area IS DISTINCT FROM NEW.area THEN changed_fields_array := array_append(changed_fields_array, 'area'); END IF;
  ELSIF TG_OP = 'DELETE' THEN
    action_type := 'deleted';
    old_data_json := to_jsonb(OLD);
    new_data_json := NULL;
    changed_fields_array := ARRAY[]::TEXT[];
  END IF;

  INSERT INTO public.life_milestones_history (
    milestone_id,
    user_id,
    action,
    old_data,
    new_data,
    changed_fields
  ) VALUES (
    COALESCE(NEW.id, OLD.id),
    COALESCE(NEW.user_id, OLD.user_id),
    action_type,
    old_data_json,
    new_data_json,
    changed_fields_array
  );

  RETURN COALESCE(NEW, OLD);
END;
$$;


