--
-- Name: record_api_key_error(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.record_api_key_error(_key_id uuid, _error_message text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  UPDATE public.api_keys
  SET 
    last_error = _error_message,
    error_count = error_count + 1,
    updated_at = now()
  WHERE id = _key_id;
  
  -- Auto-disable if too many errors
  UPDATE public.api_keys
  SET is_active = false
  WHERE id = _key_id AND error_count >= 5;
END;
$$;


