COPY supabase_migrations.schema_migrations (version, statements, name) FROM stdin;
20241222100000	{"-- Enable UUID extension\r\nCREATE EXTENSION IF NOT EXISTS \\"uuid-ossp\\"","-- Create profiles table to extend auth.users\r\nCREATE TABLE IF NOT EXISTS public.profiles (\r\n    id UUID REFERENCES auth.users(id) ON DELETE CASCADE PRIMARY KEY,\r\n    email TEXT,\r\n    full_name TEXT,\r\n    avatar_url TEXT,\r\n    created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL,\r\n    updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL\r\n)","-- Enable Row Level Security\r\nALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY","-- Create policy: Users can view their own profile\r\nCREATE POLICY \\"Users can view own profile\\"\r\n    ON public.profiles FOR SELECT\r\n    USING (auth.uid() = id)","-- Create policy: Users can update their own profile\r\nCREATE POLICY \\"Users can update own profile\\"\r\n    ON public.profiles FOR UPDATE\r\n    USING (auth.uid() = id)","-- Create policy: Users can insert their own profile\r\nCREATE POLICY \\"Users can insert own profile\\"\r\n    ON public.profiles FOR INSERT\r\n    WITH CHECK (auth.uid() = id)","-- Function to automatically create a profile when a user signs up\r\nCREATE OR REPLACE FUNCTION public.handle_new_user()\r\nRETURNS TRIGGER AS $$\r\nBEGIN\r\n    INSERT INTO public.profiles (id, email, full_name)\r\n    VALUES (\r\n        NEW.id,\r\n        NEW.email,\r\n        COALESCE(NEW.raw_user_meta_data->>'full_name', '')\r\n    );\r\n    RETURN NEW;\r\nEND;\r\n$$ LANGUAGE plpgsql SECURITY DEFINER","-- Trigger to call the function when a new user is created\r\nCREATE OR REPLACE TRIGGER on_auth_user_created\r\n    AFTER INSERT ON auth.users\r\n    FOR EACH ROW EXECUTE FUNCTION public.handle_new_user()","-- Function to update updated_at timestamp\r\nCREATE OR REPLACE FUNCTION public.handle_updated_at()\r\nRETURNS TRIGGER AS $$\r\nBEGIN\r\n    NEW.updated_at = NOW();\r\n    RETURN NEW;\r\nEND;\r\n$$ LANGUAGE plpgsql","-- Trigger to automatically update updated_at\r\nCREATE OR REPLACE TRIGGER set_updated_at\r\n    BEFORE UPDATE ON public.profiles\r\n    FOR EACH ROW\r\n    EXECUTE FUNCTION public.handle_updated_at()","-- Create todos table as an example\r\nCREATE TABLE IF NOT EXISTS public.todos (\r\n    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,\r\n    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,\r\n    title TEXT NOT NULL,\r\n    description TEXT,\r\n    completed BOOLEAN DEFAULT FALSE NOT NULL,\r\n    created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL,\r\n    updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL\r\n)","-- Enable Row Level Security on todos\r\nALTER TABLE public.todos ENABLE ROW LEVEL SECURITY","-- Create policy: Users can view their own todos\r\nCREATE POLICY \\"Users can view own todos\\"\r\n    ON public.todos FOR SELECT\r\n    USING (auth.uid() = user_id)","-- Create policy: Users can insert their own todos\r\nCREATE POLICY \\"Users can insert own todos\\"\r\n    ON public.todos FOR INSERT\r\n    WITH CHECK (auth.uid() = user_id)","-- Create policy: Users can update their own todos\r\nCREATE POLICY \\"Users can update own todos\\"\r\n    ON public.todos FOR UPDATE\r\n    USING (auth.uid() = user_id)","-- Create policy: Users can delete their own todos\r\nCREATE POLICY \\"Users can delete own todos\\"\r\n    ON public.todos FOR DELETE\r\n    USING (auth.uid() = user_id)","-- Trigger to automatically update updated_at on todos\r\nCREATE OR REPLACE TRIGGER set_todos_updated_at\r\n    BEFORE UPDATE ON public.todos\r\n    FOR EACH ROW\r\n    EXECUTE FUNCTION public.handle_updated_at()","-- Create index on user_id for better query performance\r\nCREATE INDEX IF NOT EXISTS idx_todos_user_id ON public.todos(user_id)","CREATE INDEX IF NOT EXISTS idx_todos_completed ON public.todos(completed)"}	initial_schema
